sparql:
PREFIX sc: <http://www.semanticweb.org/skincancer_exp#>
SELECT ?cancer WHERE { 
  ?cancer rdfs:subClassOf sc:SkinCancer .
  ?cancer sc:hasRiskFactor sc:FairSkin .
}

PREFIX sc: <http://www.semanticweb.org/skincancer_exp#>
SELECT ?cancer WHERE {
  ?symptom rdfs:label "sc:Itching" .
  ?symptom sc:hasSymptom ?cancer .
}

PREFIX sc: <http://www.semanticweb.org/skincancer_exp#>
SELECT ?cancer (sc:hasSymptom | sc:hasRiskFactor | sc:treatedWith | sc:diagnosedBy) ?symptom
WHERE {
  ?symptom rdfs:label "nevus" .
  ?cancer sc:commonlyFoundOn sc:Face .
}

PREFIX sc: <http://www.semanticweb.org/skincancer_exp#>
SELECT ?cancer ?danger WHERE {
  ?cancer rdfs:subClassOf sc:SkinCancer .
  ?cancer sc:hasSymptom ?symptom .
  ?symptom sc:hasDanger ?danger
}

